def Ra(Ts: Float64, Ta: Float64) -> Float64:
    var sigma: Float64 = 5.67e-08
    var epsilon: Float64 = 0.97
    var hc: Float64 = 17.4
    var phi_rad: Float64 = 0.85
    var hr: Float64 = epsilon * phi_rad * sigma * (pow(Ts, 2) + pow(Ta, 2)) * (Ts + Ta)
    return 1.0 / (hc + hr)

