def rotAzmDiffDeg(AzmA: Float64, AzmB: Float64) -> Float64:
    var diff: Float64 = AzmB - AzmA
    if diff > 180.0:
        diff = 360.0 - diff
    elif diff < -180.0:
        diff = 360.0 + diff
    return abs(diff)

def SafeDiv(a: Float64, b: Float64) -> Float64:
    if abs(b) < SMALL:
        return a / sign(SMALL, b)
    return a / b

def calculateOperationalFraction(offTemperature: Float64, controlTemperature: Float64, throttlingRange: Float64) -> Float64:
    var temperatureDifference: Float64 = abs(offTemperature - controlTemperature)
    if temperatureDifference <= 0.0:
        return 0.0
    if throttlingRange < 0.001:
        return 1.0
    return min(temperatureDifference / throttlingRange, 1.0)

def calcFluxWeightingFactor(weightedHeatFlux: Float64, uniformHeatFlux: Float64) -> Float64:
    var returnValue: Float64 = 0
    var tolerance: Float64 = 1.0e-06
    if abs(uniformHeatFlux) <= tolerance:
        returnValue = 1.0
    else:
        returnValue = weightedHeatFlux / uniformHeatFlux
    return returnValue

def interpSetPoint(LowVal: Float64, HighVal: Float64, RefVal: Float64, SetptAtLowVal: Float64, SetptAtHighVal: Float64) -> Float64:
    if LowVal >= HighVal:
        return 0.5 * (SetptAtLowVal + SetptAtHighVal)
    if RefVal <= LowVal:
        return SetptAtLowVal
    if RefVal >= HighVal:
        return SetptAtHighVal
    return SetptAtLowVal - ((RefVal - LowVal) / (HighVal - LowVal)) * (SetptAtLowVal - SetptAtHighVal)

def CalcRelativeAirVelocity(AirVel: Float64, ActMet: Float64) -> Float64:
    if ActMet > 1:
        return AirVel + 0.3 * (ActMet - 1)
    return AirVel

def CalcSatVapPressFromTemp(Temp: Float64) -> Float64:
    var XT: Float64 = Temp / 100.0
    return 6.16796 + 358.1855 * XT**2 - 550.3543 * XT**3 + 1048.8115 * XT**4

